//Envio el XML al Server
function sendToServer()
{
	proxy=GetProxy();
	proxy.StoreService().SetUserStore("PRE_IDSLegajos", array2string(arrA));

	return true;
}

function ACCEPT()
{
	sendToServer();
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}
function Guardar()
{  	
 	Ctrl('legajos').DelAllRow();
 	for (key in arrA)
 	{ 
 		var rowLeg = Ctrl('legajos').AddRow();
 		rowLeg.SetAttr('id', key.substr(1));
 		rowLeg.SetAttr('persona', arrA[key].associatedELE.getAttribute("e_numero_legajo") + " - " + arrA[key].associatedELE.getAttribute("d_ape_y_nom"));
 	}

	Ctrl("main").DoEvent("SAVE");
}

qry:select.qry:xquery:
					for $r in sql('
SELECT
	L.oi_legajo,
	L.e_numero_legajo,
	L.d_legajo
FROM
	PRE05_LEGAJOS AS L                                     
	{%?('##oi_convenio##'!='' or '##oi_categoria##'!='' or '##c_ultimo_nivel##'!='' or '##oi_concepto##'!='') 
	{% ,PRE05_DET_CONCEPTOS AS C JOIN L.oi_legajo LEFT OUTER C.oi_legajo %} {% %} %}	
WHERE 
	1=1
			{%?('##oi_escenario##'!='') {% and L.oi_escenario= ##oi_escenario## %} {% %} %}			
			{%?('##d_legajo##'!='') {% and contain(L.d_legajo, \'##d_legajo##\') %} {% %} %}
			{%?('##legajo_desde##'!='') {% and L.e_numero_legajo>= ##legajo_desde## %} {% %} %}
			{%?('##legajo_hasta##'!='') {% and L.e_numero_legajo<= ##legajo_hasta## %} {% %} %}
			{%?('##oi_grupo##'!='') {% and L.oi_grupo= ##oi_grupo## %} {% %} %}	

			{%?('##c_ultimo_nivel##'!='') {% and C.c_ultimo_nivel= \'##c_ultimo_nivel##\' %} {% %} %}	
			{%?('##oi_convenio##'!='') {% and C.oi_categoria in (select s.oi_categoria from org18_categorias as s where s.oi_convenio = ##oi_convenio##) %} {% %} %}	
			{%?('##oi_categoria##'!='') {% and C.oi_categoria= ##oi_categoria## %} {% %} %}	
			{%?('##oi_concepto##'!='' and '##oi_detalle_concepto##'!='') {% and C.oi_concepto= ##oi_concepto## 
										  and C.oi_detalle_pres = ##oi_detalle_concepto##
				{%?('##n_valor_desde##'!='') {% and C.n_valor_final>= ##n_valor_desde## %} {% %} %}	
				{%?('##n_valor_hasta##'!='') {% and C.n_valor_final<= ##n_valor_hasta## %} {% %} %}	
			%} 
			{% %} %}	

		ORDER BY e_numero_legajo ASC
		')/ROWS/ROW
